input.command:
f="articles/2025/12/27/articles.jsonl"; g="articles/2025/12/28/articles.jsonl"
echo "=== AFCON results headlines Dec 27-28 ==="
cat "$f" "$g" 2>/dev/null | python3 -c "
import sys,json,re
seen=set()
for line in sys.stdin:
    try: a=json.loads(line)
    except: continue
    t=a.get('title','')
    if re.search(r'AFCON|Africa Cup|Morocco|Mali|Senegal|Nigeria|Tunisia|DR Congo|Ivory Coast|Cameroon',t,re.I):
        if t not in seen:
            seen.add(t); print('-',(a.get('source','?'))[:18],'|',a.get('date_publish','?')[:10],'|',t[:120])
" | sort -u | head -25
